:root {
  /* =========================================
     DESIGN TOKENS — Alizé Fleurs
     Le Bouveret, bord du Léman
     Style : lacustre-lumineux | 2026-06-18
  ========================================= */

  /* ── Couleurs primaires — Bleu Léman ─── */
  --color-primary:      #1E6A85; /* 6.1:1 sur blanc — WCAG AA */
  --color-primary-dark: #155570; /* 7.8:1 sur blanc — hover/focus */
  --color-primary-light:#2A7B9E; /* 4.8:1 — grand texte uniquement */
  --color-primary-pale: #D6EBF4;

  /* ── Accent — Turquoise lacustre ──────── */
  --color-accent:       #4AB5C4; /* décoratif uniquement sur fond blanc */
  --color-accent-dark:  #329BAA;
  --color-accent-pale:  #B8E4EC;

  /* ── Vert d'eau ──────────────────────── */
  --color-water-green:      #9DD4C4;
  --color-water-green-pale: #D4EEE9;

  /* ── Sable doré lumineux ─────────────── */
  --color-sand:       #CAB07E; /* 5.7:1 sur nuit — étoiles, accents */
  --color-sand-light: #EDE0CC;
  --color-sand-pale:  #F5EDD9;

  /* ── Bleu nuit — sections sombres ────── */
  --color-night:     #1A3A4E; /* 11.4:1 blanc dessus — WCAG AAA */
  --color-night-mid: #1F4C63;

  /* ── Surfaces & fonds ────────────────── */
  --color-surface:      #FFFFFF;
  --color-surface-alt:  #F7F5F2; /* blanc nacré — fond général du site */
  --color-surface-blue: #EDF5F9;
  --color-background:   #F7F5F2;

  /* ── Textes ──────────────────────────── */
  --color-text-primary:    #12232E; /* 16.1:1 sur blanc — WCAG AAA */
  --color-text-secondary:  #2C4A5A; /*  9.4:1 sur blanc — WCAG AAA */
  --color-text-muted:      #4E6B7A; /*  5.7:1 sur blanc — WCAG AA  */
  --color-text-on-primary: #FFFFFF;
  --color-text-on-dark:    #FFFFFF;
  --color-text-on-dark-muted: rgba(255,255,255,0.72);

  /* ── Bordures ────────────────────────── */
  --color-border:       #D4E4EC;
  --color-border-light: #EAF1F5;
  --color-border-focus: #1E6A85;

  /* ── Sections spécifiques ────────────── */
  --section-mariage-bg:     #1A3A4E;
  --section-mariage-accent: #4AB5C4;
  --section-mariage-gold:   #CAB07E;
  --section-deuil-bg:       #F7F5F2;
  --footer-bg:              #1A3A4E;
  --footer-link:            #4AB5C4;
  --footer-border:          rgba(255,255,255,0.12);

  /* ── Sémantique UI ───────────────────── */
  --color-error:       #C0392B; /* 5.4:1 — WCAG AA */
  --color-error-bg:    #FDECEA;
  --color-success:     #1A7A45; /* 5.4:1 — WCAG AA */
  --color-success-bg:  #E8F8EE;
  --color-warning:     #926200; /* 5.3:1 — WCAG AA */
  --color-warning-bg:  #FEF3C7;

  /* ── Typographies ────────────────────── */
  --font-heading: 'Cormorant Garamond', Georgia, 'Times New Roman', serif;
  --font-body:    'Jost', system-ui, -apple-system, sans-serif;
  --font-accent:  'Dancing Script', cursive;

  /* ── Échelle typographique ───────────── */
  --text-xs:   0.75rem;   /*  12px */
  --text-sm:   0.875rem;  /*  14px */
  --text-base: 1rem;      /*  16px */
  --text-lg:   1.125rem;  /*  18px */
  --text-xl:   1.25rem;   /*  20px */
  --text-2xl:  1.5rem;    /*  24px */
  --text-3xl:  1.875rem;  /*  30px */
  --text-4xl:  2.25rem;   /*  36px */
  --text-5xl:  3rem;      /*  48px */
  --text-6xl:  3.75rem;   /*  60px */

  /* ── Graisses ────────────────────────── */
  --font-light:    300;
  --font-regular:  400;
  --font-medium:   500;
  --font-semibold: 600;

  /* ── Hauteurs de ligne ───────────────── */
  --leading-tight:   1.25;
  --leading-snug:    1.375;
  --leading-normal:  1.5;
  --leading-relaxed: 1.625;
  --leading-loose:   2.0;

  /* ── Tracking ────────────────────────── */
  --tracking-tight:   -0.025em;
  --tracking-snug:    -0.01em;
  --tracking-normal:  0em;
  --tracking-wide:    0.025em;
  --tracking-wider:   0.05em;
  --tracking-widest:  0.1em;

  /* ── Espacement (base 4px) ───────────── */
  --space-1:  0.25rem;  /*  4px */
  --space-2:  0.5rem;   /*  8px */
  --space-3:  0.75rem;  /* 12px */
  --space-4:  1rem;     /* 16px */
  --space-5:  1.25rem;  /* 20px */
  --space-6:  1.5rem;   /* 24px */
  --space-8:  2rem;     /* 32px */
  --space-10: 2.5rem;   /* 40px */
  --space-12: 3rem;     /* 48px */
  --space-16: 4rem;     /* 64px */
  --space-20: 5rem;     /* 80px */
  --space-24: 6rem;     /* 96px */

  /* ── Border radius ───────────────────── */
  --radius-sm:   4px;
  --radius-md:   8px;
  --radius-lg:   12px;   /* boutons CTA */
  --radius-xl:   16px;   /* cartes de service */
  --radius-2xl:  24px;
  --radius-3xl:  32px;
  --radius-full: 9999px; /* badges, tags, pilules */

  /* ── Ombres ──────────────────────────── */
  --shadow-sm:      0 1px 3px rgba(18,35,46,0.07);
  --shadow-md:      0 4px 12px rgba(18,35,46,0.09);
  --shadow-lg:      0 8px 24px rgba(18,35,46,0.11);
  --shadow-xl:      0 16px 48px rgba(18,35,46,0.14);
  --shadow-primary: 0 4px 20px rgba(30,106,133,0.28);
  --shadow-accent:  0 4px 16px rgba(74,181,196,0.30);
  --shadow-card:    0 2px 16px rgba(18,35,46,0.08);
  --shadow-inner:   inset 0 2px 4px rgba(18,35,46,0.06);

  /* ── Animations ──────────────────────── */
  --duration-fast:   150ms;
  --duration-normal: 250ms;
  --duration-slow:   400ms;
  --duration-xslow:  600ms;
  --ease-default:    cubic-bezier(0.4,0,0.2,1);
  --ease-spring:     cubic-bezier(0.34,1.56,0.64,1);
  --ease-out:        cubic-bezier(0,0,0.2,1);

  /* ── Focus ring ──────────────────────── */
  --focus-ring: 0 0 0 3px rgba(30,106,133,0.25);

  /* ── Composants ──────────────────────── */
  --nav-height:         72px;
  --btn-radius:         var(--radius-lg);
  --input-radius:       var(--radius-md);
  --card-radius:        var(--radius-xl);
  --section-padding-y:  var(--space-20);
  --container-max:      1200px;
  --container-narrow:   768px;

  /* ── Breakpoints (ref. media queries) ── */
  /* sm:640px md:768px lg:1024px xl:1280px 2xl:1536px */
}
